from django.contrib.auth.signals import user_logged_in
from django.dispatch import receiver
from saml2.response import SamlResponse

@receiver(user_logged_in)
def update_user_session(sender, request, user, **kwargs):
    if isinstance(request.saml_response, SamlResponse):
        # Extract additional attributes from SAML assertion
        attributes = request.saml_response.get_attributes()
        user.first_name = attributes.get('FirstName', '')
        user.last_name = attributes.get('LastName', '')
        user.email = attributes.get('Email', '')
        user.save()

